import React from 'react';
import { SSEDashboard } from './SSEDashboard';
import './styles.css';

export default function App() {
  return (
    <div style={{ padding: '2rem', fontFamily: 'system-ui, sans-serif', maxWidth: '36rem' }}>
      <h1 style={{ marginBottom: '1.5rem' }}>Real-Time Events</h1>
      <SSEDashboard url="/api/events" reconnectDelay={3000} />
    </div>
  );
}

import React, { useState, useRef, useCallback, useEffect } from 'react';
import './styles.css';

type EventType = 'notification' | 'alert' | 'heartbeat';
const EVENT_TYPES: EventType[] = ['notification', 'alert', 'heartbeat'];

interface SSEEvent {
  id: number;
  type: EventType;
  message: string;
  timestamp: string;
}

interface SSEDashboardProps {
  url: string;
  reconnectDelay: number;
}

// TODO: Implement SSE consumer
// 1. Connect via EventSource on button click
// 2. Handle named event types
// 3. Track connection status
// 4. Auto-reconnect on error
// 5. Filter displayed events by type
// 6. Clean up on disconnect/unmount

export const SSEDashboard: React.FC<SSEDashboardProps> = ({ url, reconnectDelay }) => {
  const [status, setStatus] = useState<'disconnected' | 'connecting' | 'connected'>('disconnected');
  const [events, setEvents] = useState<SSEEvent[]>([]);
  const [filters, setFilters] = useState<Set<EventType>>(new Set(EVENT_TYPES));
  const [connectedAt, setConnectedAt] = useState<number | null>(null);
  const [elapsed, setElapsed] = useState(0);
  // TODO: refs for EventSource, reconnect timer, elapsed timer, event counter

  const filteredEvents = events.filter(e => filters.has(e.type));

  const connect = () => {
    // TODO
  };

  const disconnect = () => {
    // TODO
  };

  const toggleFilter = (type: EventType) => {
    setFilters(prev => {
      const next = new Set(prev);
      if (next.has(type)) next.delete(type);
      else next.add(type);
      return next;
    });
  };

  // TODO: cleanup on unmount
  // TODO: elapsed timer

  return (
    <div className="sse">
      <div className="sse__controls">
        {status === 'disconnected' ? (
          <button data-testid="connect-btn" className="sse__btn sse__btn--connect" onClick={connect}>
            Connect
          </button>
        ) : (
          <button data-testid="disconnect-btn" className="sse__btn sse__btn--disconnect" onClick={disconnect}>
            Disconnect
          </button>
        )}
        <span
          data-testid="connection-status"
          className={`sse__status sse__status--${status}`}
        >
          {status}
        </span>
      </div>

      <div className="sse__meta">
        <span data-testid="event-count">Events: {events.length}</span>
        {connectedAt && (
          <span data-testid="connection-time">Connected: {elapsed}s</span>
        )}
      </div>

      <div className="sse__filters">
        {EVENT_TYPES.map(type => (
          <label key={type} className="sse__filter">
            <input
              data-testid={`filter-${type}`}
              type="checkbox"
              checked={filters.has(type)}
              onChange={() => toggleFilter(type)}
            />
            {type}
          </label>
        ))}
      </div>

      <div data-testid="event-list" className="sse__list">
        {filteredEvents.map((event, i) => (
          <div
            key={event.id}
            data-testid={`event-${i}`}
            className={`sse__event sse__event--${event.type}`}
          >
            <span className="sse__event-type">{event.type}</span>
            <span className="sse__event-msg">{event.message}</span>
            <span className="sse__event-ts">{event.timestamp}</span>
          </div>
        ))}
      </div>
    </div>
  );
};

