import { render, screen, fireEvent, waitFor, act } from '@testing-library/react';
import '@testing-library/jest-dom';
import React from 'react';

type EventHandler = (e: MessageEvent) => void;

class MockEventSource {
  static instances: MockEventSource[] = [];
  url: string;
  readyState = 0;
  onopen: (() => void) | null = null;
  onmessage: ((e: MessageEvent) => void) | null = null;
  onerror: (() => void) | null = null;
  private handlers: Record<string, EventHandler[]> = {};

  constructor(url: string) {
    this.url = url;
    MockEventSource.instances.push(this);
    setTimeout(() => {
      this.readyState = 1;
      this.onopen?.();
    }, 0);
  }

  addEventListener(type: string, handler: EventHandler) {
    if (!this.handlers[type]) this.handlers[type] = [];
    this.handlers[type].push(handler);
  }

  removeEventListener(type: string, handler: EventHandler) {
    if (this.handlers[type]) {
      this.handlers[type] = this.handlers[type].filter(h => h !== handler);
    }
  }

  emit(type: string, data: string) {
    const event = new MessageEvent(type, { data });
    if (type === 'message') {
      this.onmessage?.(event);
    }
    this.handlers[type]?.forEach(h => h(event));
  }

  close() {
    this.readyState = 2;
  }
}

(window as any).EventSource = MockEventSource;

beforeEach(() => {
  MockEventSource.instances = [];
});

import App from './App';

describe('SSE Dashboard', () => {
  it('shows connect button initially', () => {
    render(<App />);
    expect(screen.getByTestId('connect-btn')).toBeInTheDocument();
    expect(screen.getByTestId('connection-status')).toHaveTextContent('disconnected');
  });

  it('connects on button click', async () => {
    render(<App />);
    fireEvent.click(screen.getByTestId('connect-btn'));
    await waitFor(() => {
      expect(screen.getByTestId('connection-status')).toHaveTextContent('connected');
    });
  });

  it('shows disconnect button when connected', async () => {
    render(<App />);
    fireEvent.click(screen.getByTestId('connect-btn'));
    await waitFor(() => {
      expect(screen.getByTestId('disconnect-btn')).toBeInTheDocument();
    });
  });

  it('creates EventSource with correct URL', () => {
    render(<App />);
    fireEvent.click(screen.getByTestId('connect-btn'));
    expect(MockEventSource.instances.length).toBe(1);
    expect(MockEventSource.instances[0].url).toBe('/api/events');
  });

  it('displays received events', async () => {
    render(<App />);
    fireEvent.click(screen.getByTestId('connect-btn'));
    await waitFor(() => {
      expect(screen.getByTestId('connection-status')).toHaveTextContent('connected');
    });
    act(() => {
      MockEventSource.instances[0].emit('notification', JSON.stringify({ message: 'Hello!' }));
    });
    await waitFor(() => {
      expect(screen.getByTestId('event-0')).toBeInTheDocument();
    });
  });

  it('updates event count', async () => {
    render(<App />);
    fireEvent.click(screen.getByTestId('connect-btn'));
    await waitFor(() => {
      expect(screen.getByTestId('connection-status')).toHaveTextContent('connected');
    });
    act(() => {
      MockEventSource.instances[0].emit('notification', JSON.stringify({ message: 'A' }));
    });
    await waitFor(() => {
      expect(screen.getByTestId('event-count')).toHaveTextContent('1');
    });
  });

  it('shows filter checkboxes', () => {
    render(<App />);
    expect(screen.getByTestId('filter-notification')).toBeInTheDocument();
    expect(screen.getByTestId('filter-alert')).toBeInTheDocument();
    expect(screen.getByTestId('filter-heartbeat')).toBeInTheDocument();
  });

  it('disconnects and closes EventSource', async () => {
    render(<App />);
    fireEvent.click(screen.getByTestId('connect-btn'));
    await waitFor(() => {
      expect(screen.getByTestId('connection-status')).toHaveTextContent('connected');
    });
    const source = MockEventSource.instances[0];
    fireEvent.click(screen.getByTestId('disconnect-btn'));
    expect(source.readyState).toBe(2);
  });
});

