import React, { useState, useRef, useCallback, useEffect } from 'react';
import './styles.css';

type EventType = 'notification' | 'alert' | 'heartbeat';
const EVENT_TYPES: EventType[] = ['notification', 'alert', 'heartbeat'];

interface SSEEvent {
  id: number;
  type: EventType;
  message: string;
  timestamp: string;
}

interface SSEDashboardProps {
  url: string;
  reconnectDelay: number;
}

export const SSEDashboard: React.FC<SSEDashboardProps> = ({ url, reconnectDelay }) => {
  const [status, setStatus] = useState<'disconnected' | 'connecting' | 'connected'>('disconnected');
  const [events, setEvents] = useState<SSEEvent[]>([]);
  const [filters, setFilters] = useState<Set<EventType>>(new Set(EVENT_TYPES));
  const [connectedAt, setConnectedAt] = useState<number | null>(null);
  const [elapsed, setElapsed] = useState(0);
  const sourceRef = useRef<EventSource | null>(null);
  const reconnectTimerRef = useRef<number | null>(null);
  const elapsedTimerRef = useRef<number | null>(null);
  const counterRef = useRef(0);

  const filteredEvents = events.filter(e => filters.has(e.type));

  const handleEvent = useCallback((type: EventType) => (e: MessageEvent) => {
    const parsed = JSON.parse(e.data);
    const entry: SSEEvent = {
      id: counterRef.current++,
      type,
      message: parsed.message || String(parsed),
      timestamp: new Date().toLocaleTimeString(),
    };
    setEvents(prev => [entry, ...prev]);
  }, []);

  const connect = useCallback(() => {
    setStatus('connecting');
    const source = new EventSource(url);
    sourceRef.current = source;

    source.onopen = () => {
      setStatus('connected');
      const now = Date.now();
      setConnectedAt(now);
      setElapsed(0);
      elapsedTimerRef.current = window.setInterval(() => {
        setElapsed(Math.floor((Date.now() - now) / 1000));
      }, 1000);
    };

    EVENT_TYPES.forEach(type => {
      source.addEventListener(type, handleEvent(type) as EventListener);
    });

    source.onerror = () => {
      source.close();
      setStatus('disconnected');
      if (elapsedTimerRef.current) clearInterval(elapsedTimerRef.current);
      reconnectTimerRef.current = window.setTimeout(() => {
        connect();
      }, reconnectDelay);
    };
  }, [url, reconnectDelay, handleEvent]);

  const disconnect = useCallback(() => {
    if (reconnectTimerRef.current) {
      clearTimeout(reconnectTimerRef.current);
      reconnectTimerRef.current = null;
    }
    if (elapsedTimerRef.current) {
      clearInterval(elapsedTimerRef.current);
      elapsedTimerRef.current = null;
    }
    sourceRef.current?.close();
    sourceRef.current = null;
    setStatus('disconnected');
    setConnectedAt(null);
  }, []);

  const toggleFilter = (type: EventType) => {
    setFilters(prev => {
      const next = new Set(prev);
      if (next.has(type)) next.delete(type);
      else next.add(type);
      return next;
    });
  };

  useEffect(() => {
    return () => {
      sourceRef.current?.close();
      if (reconnectTimerRef.current) clearTimeout(reconnectTimerRef.current);
      if (elapsedTimerRef.current) clearInterval(elapsedTimerRef.current);
    };
  }, []);

  return (
    <div className="sse">
      <div className="sse__controls">
        {status === 'disconnected' ? (
          <button data-testid="connect-btn" className="sse__btn sse__btn--connect" onClick={connect}>
            Connect
          </button>
        ) : (
          <button data-testid="disconnect-btn" className="sse__btn sse__btn--disconnect" onClick={disconnect}>
            Disconnect
          </button>
        )}
        <span data-testid="connection-status" className={`sse__status sse__status--${status}`}>
          {status}
        </span>
      </div>

      <div className="sse__meta">
        <span data-testid="event-count">Events: {events.length}</span>
        {connectedAt && (
          <span data-testid="connection-time">Connected: {elapsed}s</span>
        )}
      </div>

      <div className="sse__filters">
        {EVENT_TYPES.map(type => (
          <label key={type} className="sse__filter">
            <input
              data-testid={`filter-${type}`}
              type="checkbox"
              checked={filters.has(type)}
              onChange={() => toggleFilter(type)}
            />
            {type}
          </label>
        ))}
      </div>

      <div data-testid="event-list" className="sse__list">
        {filteredEvents.map((event, i) => (
          <div
            key={event.id}
            data-testid={`event-${i}`}
            className={`sse__event sse__event--${event.type}`}
          >
            <span className="sse__event-type">{event.type}</span>
            <span className="sse__event-msg">{event.message}</span>
            <span className="sse__event-ts">{event.timestamp}</span>
          </div>
        ))}
      </div>
    </div>
  );
};
